<?php
namespace Tests\Feature;use App\Domain\Shops\ShopSaleReadService;use App\Models\Character;use App\Models\CharacterEquipment;use App\Models\CharacterItem;use App\Models\Item;use App\Models\ItemInstance;use App\Models\Shop;use Illuminate\Foundation\Testing\RefreshDatabase;use Illuminate\Support\Str;use Tests\TestCase;
final class ShopSaleReadServiceTest extends TestCase{use RefreshDatabase;public function test_catalog_prepares_stacks_instances_prices_and_excludes_sold(){$c=Character::factory()->selected()->create();$stack=$this->item(true);CharacterItem::create(['character_id'=>$c->id,'item_id'=>$stack->id,'quantity'=>10,'locked_quantity'=>3]);$unique=$this->item(false);$available=ItemInstance::factory()->create(['character_id'=>$c->id,'item_id'=>$unique->id,'refinement_level'=>5]);$equipped=ItemInstance::factory()->equipped()->create(['character_id'=>$c->id,'item_id'=>$unique->id]);CharacterEquipment::create(['character_id'=>$c->id,'slot'=>'main_hand','item_instance_id'=>$equipped->id,'equipped_at'=>now()]);$sold=ItemInstance::factory()->sold()->create(['character_id'=>$c->id,'item_id'=>$unique->id]);$shop=Shop::factory()->create(['buys_items'=>true,'purchase_rate_basis_points'=>5000]);$result=app(ShopSaleReadService::class)->catalog($c->user,$c,$shop)->toArray();$this->assertTrue($result['shop_can_buy']);$this->assertSame(2,$result['sellable_count']);$rows=collect($result['entries']);$stackRow=$rows->firstWhere('source_type','stack');$this->assertSame(7,$stackRow['available_quantity']);$this->assertSame(5,$stackRow['unit_gold']);$this->assertSame(35,$stackRow['max_total_gold']);$this->assertSame('partially_locked',$stackRow['warning_code']);$this->assertSame(5,$rows->firstWhere('item_instance_uuid',$available->uuid)['refinement_level']);$this->assertSame('equipped',$rows->firstWhere('item_instance_uuid',$equipped->uuid)['blocked_reason_code']);$this->assertNull($rows->firstWhere('item_instance_uuid',$sold->uuid));}
public function test_non_buying_shop_returns_empty_and_foreign_inventory_never_appears(){$c=Character::factory()->selected()->create();$foreign=Character::factory()->create();$item=$this->item(true);CharacterItem::create(['character_id'=>$foreign->id,'item_id'=>$item->id,'quantity'=>5,'locked_quantity'=>0]);$shop=Shop::factory()->create(['buys_items'=>false]);$result=app(ShopSaleReadService::class)->catalog($c->user,$c,$shop)->toArray();$this->assertFalse($result['shop_can_buy']);$this->assertSame([],$result['entries']);$this->assertSame(0,$result['sellable_count']);}
public function test_blocked_reasons_are_stable(){$c=Character::factory()->selected()->create();$item=$this->item(true,['is_sellable'=>false]);CharacterItem::create(['character_id'=>$c->id,'item_id'=>$item->id,'quantity'=>2,'locked_quantity'=>2]);$shop=Shop::factory()->create(['buys_items'=>true]);$row=app(ShopSaleReadService::class)->catalog($c->user,$c,$shop)->toArray()['entries'][0];$this->assertFalse($row['can_sell']);$this->assertSame('item_not_sellable',$row['blocked_reason_code']);}
private function item($stack,array $extra=[]){return Item::create(array_merge(['code'=>'read_'.Str::random(10),'name'=>'Read item','item_type'=>$stack?'material':'equipment','equipment_type'=>$stack?null:'weapon','rarity'=>'common','is_stackable'=>$stack,'max_stack'=>$stack?99:1,'is_sellable'=>true,'sell_price'=>10,'status'=>'active'],$extra));}}
